SELECT /* base.ec.pd :: PdhProdChgHist :: selectList */ h.* , ste.site_nm AS site_nm FROM pdh_prod_chg_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id
ORDER BY h.prod_chg_hist_id ASC ORDER BY h.prod_chg_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.pd :: PdhProdChgHist :: selectPageList */ h.* , ste.site_nm AS site_nm FROM pdh_prod_chg_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id
ORDER BY h.prod_chg_hist_id ASC ORDER BY h.prod_chg_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{limit} OFFSET #{offset}
